msg.method = "POST";
msg.url = env.get("TWENTY_BASE_URL") + "/rest/notes";
msg.payload = {
    title: msg.noteTitle,
    bodyV2: { markdown: msg.noteMarkdown || "" }
};
msg.headers = {
    "Authorization": "Bearer " + msg.twentyToken,
    "Host": msg.twentyHost,
    "Content-Type": "application/json"
};
return msg;

const note = msg.payload && msg.payload.data && msg.payload.data.createNote;
const noteId = note ? note.id : '';

if (!noteId) {
    msg.noteResult = {
        success: false,
        error: 'Note creation failed',
        details: msg.payload && msg.payload.errors
    };
    return [null, msg];
}

const targets = [];
if (msg.personId) {
    targets.push({ noteId: noteId, targetPersonId: msg.personId });
}
if (msg.opportunityId) {
    targets.push({ noteId: noteId, targetOpportunityId: msg.opportunityId });
}

if (targets.length === 0) {
    msg.noteResult = { success: true, noteId: noteId, linked: 0 };
    return [null, msg];
}

msg.noteId = noteId;
const token = msg.twentyToken;
const host = msg.twentyHost;

const msgs = targets.map(payload => {
    const m = Object.assign({}, msg);
    m.method = "POST";
    m.url = env.get("TWENTY_BASE_URL") + "/rest/noteTargets";
    m.headers = {
        "Authorization": "Bearer " + token,
        "Host": host,
        "Content-Type": "application/json"
    };
    m.payload = payload;
    return m;
});

return [msgs, null];

const target = msg.payload && msg.payload.data && msg.payload.data.createNoteTarget;
msg.noteResult = {
    success: !!target,
    noteId: msg.noteId,
    error: target ? undefined : (msg.payload && msg.payload.errors)
};
return msg;

const axios = this.axios || axios;

const token = msg.twentyToken;
const host = msg.twentyHost;
const email = msg.lead.email;

const headers = {
    "Authorization": "Bearer " + token,
    "Host": host,
    "Content-Type": "application/json"
};

const BASE = env.get("TWENTY_BASE_URL");

(async () => {
    try {
        // 1. Search active people
        const activeRes = await axios.get(`${BASE}/rest/people?filter=emails.primaryEmail[eq]:${encodeURIComponent(email)}`, { headers });
        let existingPerson = activeRes.data && activeRes.data.data && activeRes.data.data.people && activeRes.data.data.people[0];
        let isDeleted = false;

        // 2. If not found, search in deleted people
        if (!existingPerson) {
            const deletedRes = await axios.get(`${BASE}/rest/people?filter=deletedAt[is]:NOT_NULL`, { headers });
            const deletedPeople = deletedRes.data && deletedRes.data.data && deletedRes.data.data.people || [];
            existingPerson = deletedPeople.find(p => p.emails && p.emails.primaryEmail && p.emails.primaryEmail.toLowerCase() === email.toLowerCase());
            if (existingPerson) {
                isDeleted = true;
            }
        }

        let url, method, body;
        if (existingPerson) {
            url = `${BASE}/rest/people/${existingPerson.id}`;
            method = 'PATCH';
            body = {};

            // Restore if it was soft-deleted
            if (isDeleted) {
                body.deletedAt = null;
            }

            // Update fields
            if (msg.lead.firstName || msg.lead.lastName) {
                body.name = {};
                if (msg.lead.firstName) body.name.firstName = msg.lead.firstName;
                if (msg.lead.lastName) body.name.lastName = msg.lead.lastName;
            }
            if (msg.jobTitle) body.jobTitle = msg.jobTitle;
            if (msg.lead.phone) body.phones = { primaryPhoneNumber: msg.lead.phone };

            // Also update invoiceNinjaClientId if passed
            if (msg.clientInfo && msg.clientInfo.id) {
                body.invoiceNinjaClientId = msg.clientInfo.id;
            }
        } else {
            url = `${BASE}/rest/people`;
            method = 'POST';
            body = {
                name: { firstName: msg.lead.firstName, lastName: msg.lead.lastName },
                emails: { primaryEmail: email },
                jobTitle: msg.jobTitle
            };
            if (msg.lead.phone) {
                body.phones = { primaryPhoneNumber: msg.lead.phone };
            }
            if (msg.clientInfo && msg.clientInfo.id) {
                body.invoiceNinjaClientId = msg.clientInfo.id;
            }
        }

        const actionRes = await axios({
            method: method,
            url: url,
            data: body,
            headers: headers
        });

        msg.payload = actionRes.data;
        node.send(msg);
    } catch (error) {
        node.warn("Error in Search & Upsert Person: " + (error.response ? JSON.stringify(error.response.data) : error.message));
        msg.payload = error.response ? error.response.data : { error: error.message };
        node.send(msg);
    }
})();

return null;

